INSERT INTO `v1_b23c9927a7e2cc6143d5c543dffecf7d0ad0424909e3d594130ab418f6c9e453` VALUES ("", "drama_talk_surprise_loop_shy", 3, "", 0.2, "drama_talk_surprise_in_shy", 0, 6, 6014, 1, 129811);
INSERT INTO `v1_b23c9927a7e2cc6143d5c543dffecf7d0ad0424909e3d594130ab418f6c9e453` VALUES ("", 0, 21, "", "", "vo_minigame_1013_top_talk_6_002", 0, 6, 6015, "", "vo_minigame_1013");
INSERT INTO `v1_b23c9927a7e2cc6143d5c543dffecf7d0ad0424909e3d594130ab418f6c9e453` VALUES (0.3, 1, 11, 0, 0, "いやいや何でもない！\nあたしは別に変なこと\n考えてないからな！\nそれより訓練だっ！", 9, 6, 6016, 0, 129811);
INSERT INTO `v1_b23c9927a7e2cc6143d5c543dffecf7d0ad0424909e3d594130ab418f6c9e453` VALUES ("", "", 91, "", "", "", "", 6, 6017, "", 0);
