INSERT INTO `v1_b23c9927a7e2cc6143d5c543dffecf7d0ad0424909e3d594130ab418f6c9e453` VALUES ("", 0, 21, "", "", "vo_minigame_1013_top_talk_7_002", 0, 7, 7015, "", "vo_minigame_1013");
INSERT INTO `v1_b23c9927a7e2cc6143d5c543dffecf7d0ad0424909e3d594130ab418f6c9e453` VALUES (0.5, 1, 11, 0, 0, "彼らが私に逆らわずに\n努力したからこそ、\n得たものもありますし\n…感謝しておきますわ", 6, 7, 7016, 0, 129911);
INSERT INTO `v1_b23c9927a7e2cc6143d5c543dffecf7d0ad0424909e3d594130ab418f6c9e453` VALUES ("", "", 91, "", "", "", "", 7, 7017, "", 0);
