INSERT INTO `v1_b23c9927a7e2cc6143d5c543dffecf7d0ad0424909e3d594130ab418f6c9e453` VALUES ("", 0, 21, "", "", "vo_minigame_1013_top_talk_8_002", 0, 8, 8015, "", "vo_minigame_1013");
INSERT INTO `v1_b23c9927a7e2cc6143d5c543dffecf7d0ad0424909e3d594130ab418f6c9e453` VALUES (0.3, 1, 11, 0, 0, "くっ、そう言われると\n悔しいな…！\nならこの行軍訓練で\n逆転してやるぜ！", 7, 8, 8016, 0, 129811);
